require(['jquery', 'xwiki-events-bridge'], function($) {
  /**
   * Live preview when the User Directory settings are modified.
   */
  $('form.user-directory-settings').on('change', function(event) {
    // Default on user-level configuration.
    var configDocument = XWiki.currentDocument;
    if (configDocument.page !== 'UserDirectory' || configDocument.space !== 'Main') {
      // Global configuration.
      configDocument = new XWiki.Document('UserDirectoryConfiguration', 'XWiki');
    }
    var url = configDocument.getURL('get', 'customize=true');
    var data = $(this).serialize();
    var oldLiveDataContainer = $('#userdirectory.liveData').addClass('loading');
    $.get(url, data).then(html => {
      var newLiveDataContainer = $('<div/>').html(html).find('.liveData');
      oldLiveDataContainer.replaceWith(newLiveDataContainer);
      $(document).trigger('xwiki:dom:updated', {elements: newLiveDataContainer.toArray()});
    });
  });

  /**
   * User scope filtering (for sub-wikis): reload the page with the selected user scope as a URL parameter.
   */
  $('#userScopeFilter').on('change', function(event) {
    var value = $(this).val();
    var url = new URL(window.location.href);
    url.searchParams.set('userScope', value);
    window.location.href = url.toString();
  });
});
